"""Responsive shared-player scene for precomputed random-walk trajectories."""
from physics_playground.canvas.player import build_player_document
SCENE=r"""
const scene={draw(ctx,s){const w=s.transform.width,h=s.transform.height,c=s.config.diffusion||{},paths=c.paths||[],pad=35,scale=Math.min((w-2*pad)/(2*c.extent),(h-2*pad)/(2*c.extent)),cx=w/2,cy=h/2;ctx.clearRect(0,0,w,h);ctx.fillStyle='#FAFAFA';ctx.fillRect(0,0,w,h);ctx.strokeStyle='#777';ctx.lineWidth=1;ctx.beginPath();ctx.moveTo(pad,cy);ctx.lineTo(w-pad,cy);ctx.moveTo(cx,pad);ctx.lineTo(cx,h-pad);ctx.stroke();const palette=['#0072B2','#D55E00','#009E73','#CC79A7','#000000'];for(let j=0;j<paths.length;j++){const path=paths[j],last=Math.max(1,Math.floor((path.length-1)*s.fraction));ctx.strokeStyle=palette[j%palette.length];ctx.lineWidth=2;ctx.setLineDash(j%2?[5,3]:[]);ctx.beginPath();for(let i=0;i<=last;i++){const x=cx+path[i][0]*scale,y=cy-path[i][1]*scale;i?ctx.lineTo(x,y):ctx.moveTo(x,y)}ctx.stroke();const p=path[last];ctx.fillStyle=palette[j%palette.length];ctx.beginPath();ctx.arc(cx+p[0]*scale,cy-p[1]*scale,4,0,Math.PI*2);ctx.fill()}ctx.setLineDash([]);ctx.fillStyle='#111';ctx.font='14px sans-serif';ctx.fillText(`${c.dimensions}D seeded random walks`,16,24);}};
"""
def build_diffusion_document(*,paths,dimensions:int,extent:float,message:str,seed:int)->str:
    config={"durationMs":2400,"autoplay":False,"seed":seed,"tracks":[{"id":"walks","label":"Particle trajectories","x":[0,1]}],"events":[],"completionMessage":message,"diffusion":{"paths":paths,"dimensions":dimensions,"extent":max(float(extent),1e-9)},"view":{"minimum":-extent,"maximum":extent}}
    return build_player_document(config=config,scene_javascript=SCENE,logical_width=720,logical_height=520,accessible_label=f"{dimensions}-dimensional random-walk trajectories. {message}",idle_hint="Press Play to trace the seeded particle walks")
